+/* =============================================================================
+   LEARN MENU (BEGINNER MODE)
+   ============================================================================= */
+
+.learn-menu {
+  position: relative;
+}
+
+.learn-menu-trigger-icon,
+.learn-menu-trigger-chevron {
+  display: inline-flex;
+  align-items: center;
+  justify-content: center;
+  line-height: 0;
+}
+
+.learn-menu-popover {
+  position: absolute;
+  right: 0;
+  margin-top: var(--space-2);
+  min-width: 280px;
+  max-width: min(360px, 90vw);
+  background: var(--color-background-elevated);
+  border: 1px solid var(--color-border-subtle);
+  border-radius: 12px;
+  box-shadow: var(--shadow-lg, 0 12px 36px rgba(0,0,0,0.35));
+  z-index: 20;
+  padding: var(--space-2);
+}
+
+.learn-menu-section + .learn-menu-section {
+  margin-top: var(--space-2);
+  padding-top: var(--space-2);
+  border-top: 1px solid var(--color-border-subtle);
+}
+
+.learn-menu-section-title {
+  padding: var(--space-1) var(--space-2);
+  font-size: 10px;
+  letter-spacing: 0.12em;
+  text-transform: uppercase;
+  color: var(--color-text-muted);
+  user-select: none;
+}
+
+.learn-menu-item {
+  width: 100%;
+  justify-content: flex-start;
+  text-align: left;
+  padding: var(--space-3);
+  border-radius: 12px;
+  gap: var(--space-3);
+  white-space: normal;
+  line-height: 1.2;
+}
+
+.learn-menu-item.btn-ghost {
+  border-color: transparent;
+}
+
+.learn-menu-item.btn-ghost:hover {
+  border-color: var(--color-border-subtle);
+  background: var(--color-background-hover);
+}
+
+.learn-menu-item-icon {
+  width: 22px;
+  height: 22px;
+  display: inline-flex;
+  align-items: center;
+  justify-content: center;
+  flex: 0 0 22px;
+  color: var(--color-primary);
+  line-height: 0;
+}
+
+.learn-menu-item-content {
+  display: flex;
+  flex-direction: column;
+  gap: 2px;
+}
+
+.learn-menu-item-title {
+  font-weight: var(--font-semibold);
+  color: var(--color-text);
+}
+
+.learn-menu-item-desc {
+  font-size: var(--text-xs);
+  color: var(--color-text-muted);
+}
+
+/* =============================================================================
+   SETTINGS OVERLAY
+   ============================================================================= */
+
+.settings-overlay {
+  display: flex;
+  flex-direction: column;
+  gap: var(--space-4);
+}
+
+.settings-section {
+  gap: var(--space-3);
+}
+
+.settings-section-header {
+  display: flex;
+  align-items: center;
+  gap: var(--space-2);
+  color: var(--color-text);
+}
+
+.settings-section-title {
+  margin: 0;
+  font-size: var(--text-sm);
+  font-weight: var(--font-bold);
+  color: var(--color-text);
+}
+
+.settings-row {
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+  gap: var(--space-4);
+}
+
+.settings-row--top {
+  align-items: flex-start;
+}
+
+.settings-row-text {
+  flex: 1;
+  min-width: 0;
+  display: flex;
+  flex-direction: column;
+  gap: 2px;
+}
+
+.settings-row-label {
+  font-weight: var(--font-bold);
+  color: var(--color-text);
+}
+
+.settings-row-desc {
+  color: var(--color-text-muted);
+  font-size: var(--text-xs);
+  line-height: 1.4;
+}
+
+.settings-select {
+  min-width: 160px;
+  width: auto;
+  background: var(--color-background);
+  border-color: var(--color-border-light);
+}
+
+.settings-paragraph {
+  margin: var(--space-2) 0;
+  color: var(--color-text-dim);
+  line-height: 1.5;
+}
+
+.settings-meta {
+  margin: 0;
+  color: var(--color-text-muted);
+  font-size: var(--text-xs);
+}
+
+.settings-row-actions {
+  display: flex;
+  align-items: center;
+}
+
+.settings-footer {
+  display: flex;
+  justify-content: flex-end;
+}
+
+@media (max-width: 640px) {
+  .settings-row {
+    flex-direction: column;
+    align-items: stretch;
+  }
+
+  .settings-select {
+    min-width: 0;
+    width: 100%;
+  }
+
+  .settings-footer {
+    justify-content: stretch;
+  }
+
+  .settings-footer .btn {
+    width: 100%;
+  }
+}
+
+/* =============================================================================
+   GLOSSARY PANEL
+   ============================================================================= */
+
+.glossary-panel {
+  display: grid;
+  grid-template-columns: minmax(220px, 280px) 1fr;
+  gap: var(--space-3);
+  height: 100%;
+  min-height: 360px;
+  position: relative;
+}
+
+.glossary-panel__sidebar {
+  display: flex;
+  flex-direction: column;
+  gap: var(--space-2);
+  min-width: 0;
+}
+
+.glossary-panel__controls {
+  display: flex;
+  flex-direction: column;
+  gap: var(--space-2);
+}
+
+.glossary-panel__search-row {
+  display: flex;
+  gap: var(--space-2);
+  align-items: center;
+}
+
+.glossary-panel__search {
+  background: var(--color-background-alt);
+  border-color: var(--color-border-subtle);
+}
+
+.glossary-panel__chips {
+  display: flex;
+  gap: 6px;
+  overflow-x: auto;
+  padding-bottom: 2px;
+}
+
+.glossary-panel__chips--alpha {
+  flex-wrap: wrap;
+  overflow: visible;
+  padding-bottom: 0;
+}
+
+.glossary-panel__list {
+  border: 1px solid var(--color-border-subtle);
+  border-radius: var(--radius-lg);
+  overflow: hidden;
+  flex: 1;
+  min-height: 220px;
+  background: var(--color-background);
+}
+
+.glossary-panel__listbox {
+  max-height: 100%;
+  overflow-y: auto;
+  display: flex;
+  flex-direction: column;
+}
+
+.glossary-panel__term {
+  text-align: left;
+  padding: var(--space-3) var(--space-4);
+  background: transparent;
+  color: var(--color-text);
+  border: none;
+  border-bottom: 1px solid var(--color-border-subtle);
+  cursor: pointer;
+}
+
+.glossary-panel__term[aria-selected="true"] {
+  background: var(--color-background-hover);
+}
+
+.glossary-panel__term:focus-visible {
+  outline: none;
+  background: var(--color-background-hover);
+  box-shadow: inset 0 0 0 2px var(--color-border-focus);
+}
+
+.glossary-panel__term-title {
+  font-weight: var(--font-bold);
+}
+
+.glossary-panel__term-desc {
+  color: var(--color-text-muted);
+  font-size: var(--text-xs);
+}
+
+.glossary-panel__empty {
+  padding: var(--space-4);
+  color: var(--color-text-muted);
+}
+
+.glossary-panel__detail {
+  border: 1px solid var(--color-border-subtle);
+  border-radius: var(--radius-xl);
+  padding: var(--space-3) var(--space-4);
+  background: var(--color-background-alt);
+  min-height: 240px;
+}
+
+.glossary-panel__detail-header {
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+}
+
+.glossary-panel__detail-eyebrow {
+  font-size: var(--text-2xs);
+  letter-spacing: 0.12em;
+  text-transform: uppercase;
+  color: var(--color-text-muted);
+}
+
+.glossary-panel__detail-title {
+  font-size: var(--text-lg);
+  font-weight: 800;
+}
+
+.glossary-panel__detail-body {
+  margin-top: var(--space-2);
+  line-height: 1.5;
+  color: var(--color-text);
+}
+
+.glossary-panel__related {
+  margin-top: var(--space-3);
+}
+
+.glossary-panel__related-label {
+  font-size: var(--text-2xs);
+  letter-spacing: 0.12em;
+  text-transform: uppercase;
+  color: var(--color-text-muted);
+  margin-bottom: var(--space-2);
+}
+
+.glossary-panel__related-list {
+  display: flex;
+  gap: var(--space-2);
+  flex-wrap: wrap;
+}
+
+.glossary-panel__related-chip {
+  font-size: var(--text-xs);
+  padding: 4px 8px;
+  border-radius: var(--radius-lg);
+  background: rgba(34, 211, 238, 0.12);
+  color: var(--color-primary);
+  border-color: rgba(34, 211, 238, 0.24);
+  transform: none;
+}
+
+.glossary-panel__related-chip:hover {
+  transform: none;
+}
+
+.glossary-panel__empty-detail {
+  color: var(--color-text-muted);
+}
+
+@media (max-width: 720px) {
+  .glossary-panel {
+    grid-template-columns: 1fr;
+  }
+}
+
